//! Verifies `AuthorizerEngine::check()` produces the intended Permit/Deny
//! decisions against the real healthcare test dataset generated by
//! `gen_healthcare_dataset.rs` -- not synthetic fixtures, the actual CSVs in
//! `data/healthcare` (or whatever `--config-dir` names), loaded through the
//! same `arbor-connectors` -> `Graph` -> `Snapshot` pipeline the indexer
//! service uses.
//!
//! Exercises every policy shape the dataset exists to showcase:
//!   - clinic-scoped RBAC/ReBAC (`EntityWithDescendants` on both sides)
//!   - cross-clinic ReBAC via a genuine multi-parent DAG (specialty group)
//!   - ABAC consent gating on that same cross-clinic grant
//!   - forbid-overrides-permit (break-glass restricted patients)
//!   - narrow `ActionSet` referral grants (labs+imaging, not full chart)
//!   - the admin Treatment/Payment/Operations boundary (billing, not chart)
//!
//! Usage: verify_healthcare_dataset [--config-dir DIR]  (default: data/healthcare)
//!
//! Regenerate the dataset first if it doesn't exist:
//!   cargo run -p arbor-bench --bin gen_healthcare_dataset

use std::collections::HashMap;
use std::env;
use std::path::{Path, PathBuf};

use arbor_authorizer::engine::{AuthorizerEngine, Decision};
use arbor_connectors::action_id_for_name;
use arbor_indexer::{csv_source, snapshot_builder::SnapshotBuilder};
use uuid::Uuid;

fn read_rows(dir: &Path, file: &str) -> Vec<HashMap<String, String>> {
    let path = dir.join(file);
    let mut reader = csv::Reader::from_path(&path)
        .unwrap_or_else(|e| panic!("failed to open {}: {e}", path.display()));
    let headers = reader.headers().expect("headers").clone();
    reader
        .records()
        .map(|r| {
            let record = r.expect("valid csv row");
            headers.iter().zip(record.iter()).map(|(h, v)| (h.to_string(), v.to_string())).collect()
        })
        .collect()
}

fn parents(row: &HashMap<String, String>) -> Vec<Uuid> {
    row["parent_ids"]
        .split(';')
        .filter(|s| !s.is_empty())
        .map(|s| Uuid::parse_str(s).unwrap_or_else(|e| panic!("bad uuid {s:?}: {e}")))
        .collect()
}

fn uuid(row: &HashMap<String, String>, col: &str) -> Uuid {
    Uuid::parse_str(&row[col]).unwrap_or_else(|e| panic!("bad uuid in column {col:?}: {e}"))
}

/// Everything the checks below need, pulled directly from the generated
/// CSVs -- no re-derivation of the generator's internal seeds/formulas,
/// so this stays correct even if the generator's randomization changes as
/// long as the CSV shapes and policy-naming conventions don't.
struct Fixtures {
    // A physician, their home clinic, and their specialty group.
    physician: Uuid,
    physician_clinic: Uuid,
    physician_group: Uuid,
    // A patient registered at the physician's home clinic.
    home_clinic_patient: Uuid,
    // A consenting patient at a *different* clinic, reachable only via the
    // physician's specialty-group membership (the multi-parent DAG case).
    cross_clinic_consenting_patient: Uuid,
    // A non-consenting patient at a *different* clinic -- same ReBAC path,
    // should be blocked by the ABAC condition specifically.
    cross_clinic_nonconsenting_patient: Uuid,
    // A restricted patient (break-glass forbid target) at the physician's
    // own clinic, so the forbid has an otherwise-applicable permit to override.
    restricted_patient: Uuid,
    restricted_patient_physician: Uuid, // a physician at the restricted patient's own clinic
    // A referral: a physician with no other relationship to the patient.
    referral_physician: Uuid,
    referral_patient: Uuid,
    admin: Uuid,
    technician: Uuid,
    technician_other_clinic_patient: Uuid, // patient at a clinic the technician does NOT belong to
    room: Uuid,
}

fn build_fixtures(dir: &Path) -> Fixtures {
    let physicians = read_rows(dir, "physicians.csv");
    let patients = read_rows(dir, "patients.csv");
    let technicians = read_rows(dir, "technicians.csv");
    let admin_staff = read_rows(dir, "admin_staff.csv");
    let rooms = read_rows(dir, "rooms_equipment.csv");
    let policies = read_rows(dir, "policies.csv");

    // clinic_id -> roster_id, read directly off each clinic's
    // "*-staff-read-write-own-roster" policy row (principal=clinic,
    // resource=roster) rather than re-deriving the pairing from names.
    let mut roster_of_clinic: HashMap<Uuid, Uuid> = HashMap::new();
    for row in &policies {
        if row["policy_name"].ends_with("-staff-read-write-own-roster") {
            roster_of_clinic.insert(uuid(row, "principal"), uuid(row, "resource"));
        }
    }
    let clinic_of_roster: HashMap<Uuid, Uuid> =
        roster_of_clinic.iter().map(|(clinic, roster)| (*roster, *clinic)).collect();

    // Every patient targeted by a break-glass forbid -- excluded from the
    // "plain" fixture picks below, since those checks mean to isolate RBAC/
    // ReBAC/ABAC behavior specifically, not incidentally collide with a
    // forbid that correctly overrides the permit they're trying to observe.
    let restricted_patients: std::collections::HashSet<Uuid> = policies
        .iter()
        .filter(|row| row["ptype"] == "forbid" && row["principal_kind"] == "entity_type" && row["principal"] == "Physician")
        .map(|row| uuid(row, "resource"))
        .collect();

    let physician_row = &physicians[0];
    let physician = uuid(physician_row, "physician_id");
    let phys_parents = parents(physician_row);
    let physician_clinic = phys_parents[0];
    let physician_group = phys_parents[1];
    let physician_roster = roster_of_clinic[&physician_clinic];

    let patient_roster = |row: &HashMap<String, String>| parents(row)[0];
    let consents = |row: &HashMap<String, String>| row["consents_to_specialist_sharing"] == "true";
    let not_restricted = |row: &&HashMap<String, String>| !restricted_patients.contains(&uuid(row, "patient_id"));

    let home_clinic_patient = uuid(
        patients.iter().filter(not_restricted).find(|p| patient_roster(p) == physician_roster).expect("a non-restricted patient at physician's clinic"),
        "patient_id",
    );

    let cross_clinic_consenting = patients
        .iter()
        .filter(not_restricted)
        .find(|p| patient_roster(p) != physician_roster && consents(p))
        .expect("a non-restricted, consenting patient at another clinic");
    let cross_clinic_nonconsenting = patients
        .iter()
        .filter(not_restricted)
        .find(|p| patient_roster(p) != physician_roster && !consents(p))
        .expect("a non-restricted, non-consenting patient at another clinic");

    let forbid_row = policies
        .iter()
        .find(|row| row["ptype"] == "forbid" && row["principal_kind"] == "entity_type" && row["principal"] == "Physician")
        .expect("at least one restricted-patient forbid policy");
    let restricted_patient = uuid(forbid_row, "resource");
    let restricted_patient_row = patients.iter().find(|p| uuid(p, "patient_id") == restricted_patient).expect("restricted patient row");
    let restricted_patient_clinic = clinic_of_roster[&patient_roster(restricted_patient_row)];
    let restricted_patient_physician = uuid(
        physicians.iter().find(|p| parents(p)[0] == restricted_patient_clinic).expect("a physician at the restricted patient's clinic"),
        "physician_id",
    );

    let referral_row = policies.iter().find(|row| row["policy_name"].starts_with("referral-")).expect("at least one referral policy");
    let referral_physician = uuid(referral_row, "principal");
    let referral_patient = uuid(referral_row, "resource");

    let admin = uuid(&admin_staff[0], "admin_id");

    let technician_row = &technicians[0];
    let technician = uuid(technician_row, "tech_id");
    let technician_clinic = parents(technician_row)[0];
    let technician_other_clinic_patient = uuid(
        patients
            .iter()
            .filter(not_restricted)
            .find(|p| patient_roster(p) != roster_of_clinic[&technician_clinic])
            .expect("a non-restricted patient at another clinic"),
        "patient_id",
    );

    let room = uuid(&rooms[0], "room_id");

    Fixtures {
        physician,
        physician_clinic,
        physician_group,
        home_clinic_patient,
        cross_clinic_consenting_patient: uuid(cross_clinic_consenting, "patient_id"),
        cross_clinic_nonconsenting_patient: uuid(cross_clinic_nonconsenting, "patient_id"),
        restricted_patient,
        restricted_patient_physician,
        referral_physician,
        referral_patient,
        admin,
        technician,
        technician_other_clinic_patient,
        room,
    }
}

struct Check<'a> {
    name: &'a str,
    principal: Uuid,
    action: Uuid,
    resource: Uuid,
    expected: Decision,
}

fn main() {
    let mut config_dir = PathBuf::from("data/healthcare");
    let mut args = env::args().skip(1);
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--config-dir" => config_dir = PathBuf::from(args.next().expect("--config-dir needs a value")),
            other => panic!("unrecognized argument: {other}"),
        }
    }
    if !config_dir.exists() {
        panic!(
            "{} does not exist -- generate it first with:\n  cargo run -p arbor-bench --bin gen_healthcare_dataset -- --out-dir {}",
            config_dir.display(),
            config_dir.display(),
        );
    }

    println!("Loading graph from connectors in {}", config_dir.display());
    let connectors = arbor_connectors::load_connector_config(&config_dir).expect("load connectors.yaml");
    let data_model = arbor_connectors::load_data_model_config(&config_dir).expect("load data_model.yaml");
    let graph = csv_source::build_graph(&connectors, &data_model, &config_dir).expect("build graph from connectors");

    let snapshot = SnapshotBuilder::build(&graph).expect("build snapshot");
    let engine = AuthorizerEngine::from_snapshot(snapshot);

    let f = build_fixtures(&config_dir);

    let read_chart = action_id_for_name("read_chart");
    let read_labs = action_id_for_name("read_labs");
    let read_billing = action_id_for_name("read_billing");
    let room_read = action_id_for_name("read");

    let checks = vec![
        Check {
            name: "clinic staff: physician reads own-clinic patient's chart",
            principal: f.physician,
            action: read_chart,
            resource: f.home_clinic_patient,
            expected: Decision::Permit,
        },
        Check {
            name: "specialty ReBAC: physician reads consenting patient's chart at a DIFFERENT clinic (via multi-parent group)",
            principal: f.physician,
            action: read_chart,
            resource: f.cross_clinic_consenting_patient,
            expected: Decision::Permit,
        },
        Check {
            name: "ABAC gate: same specialty-group path, but patient has NOT consented",
            principal: f.physician,
            action: read_chart,
            resource: f.cross_clinic_nonconsenting_patient,
            expected: Decision::Deny,
        },
        Check {
            name: "break-glass: restricted patient's own-clinic physician is forbidden despite the clinic-wide permit",
            principal: f.restricted_patient_physician,
            action: read_chart,
            resource: f.restricted_patient,
            expected: Decision::Deny,
        },
        Check {
            name: "referral: narrow ActionSet grants labs to an otherwise-unrelated physician",
            principal: f.referral_physician,
            action: read_labs,
            resource: f.referral_patient,
            expected: Decision::Permit,
        },
        Check {
            name: "referral: the same grant does NOT extend to full chart access",
            principal: f.referral_physician,
            action: read_chart,
            resource: f.referral_patient,
            expected: Decision::Deny,
        },
        Check {
            name: "TPO boundary: admin staff read billing on any patient",
            principal: f.admin,
            action: read_billing,
            resource: f.home_clinic_patient,
            expected: Decision::Permit,
        },
        Check {
            name: "TPO boundary: admin staff do NOT get chart access",
            principal: f.admin,
            action: read_chart,
            resource: f.home_clinic_patient,
            expected: Decision::Deny,
        },
        Check {
            name: "technician: manages rooms/equipment",
            principal: f.technician,
            action: room_read,
            resource: f.room,
            expected: Decision::Permit,
        },
        Check {
            name: "technician: no chart access to a patient at another clinic (no specialty-group membership)",
            principal: f.technician,
            action: read_chart,
            resource: f.technician_other_clinic_patient,
            expected: Decision::Deny,
        },
    ];

    let mut failures = 0;
    for c in &checks {
        let principal_idx = engine.snapshot().uuid_to_index(&c.principal).unwrap_or_else(|| panic!("{}: principal not found", c.name));
        let action_idx = engine.snapshot().uuid_to_index(&c.action).unwrap_or_else(|| panic!("{}: action not found", c.name));
        let resource_idx = engine.snapshot().uuid_to_index(&c.resource).unwrap_or_else(|| panic!("{}: resource not found", c.name));

        let result = engine.check(principal_idx, action_idx, resource_idx).unwrap_or_else(|e| panic!("{}: check() failed: {e}", c.name));

        let status = if result.decision == c.expected { "OK  " } else { failures += 1; "FAIL" };
        println!("[{status}] {} -> {:?} (expected {:?})", c.name, result.decision, c.expected);
    }

    // Sanity check on the fixture-selection logic itself: the multi-parent
    // DAG and cross-clinic patients must actually be structurally distinct
    // from the "same clinic" case, or the ReBAC/ABAC checks above would pass
    // vacuously (e.g. because the "cross-clinic" patient was accidentally at
    // the physician's own clinic all along).
    assert_ne!(f.physician_clinic, f.physician_group, "sanity: clinic and group must be different entities");

    println!();
    if failures == 0 {
        println!("OK: all {} checks passed", checks.len());
    } else {
        panic!("{failures} of {} checks FAILED", checks.len());
    }
}
